-- +goose Up
-- +goose StatementBegin
-- StarWind 70-sector galaxy (phase 8.19), generated by
-- cmd/starwind-tools/convert-map. Replaces the 10-sector stub topology
-- (sectors upserted by id; gates fully replaced). Stations/grid coords
-- are out of MVP scope — do not edit by hand, rerun the converter.

ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name,
    min_x = EXCLUDED.min_x, min_y = EXCLUDED.min_y,
    max_x = EXCLUDED.max_x, max_y = EXCLUDED.max_y;

DELETE FROM gates;
-- +goose StatementEnd

-- +goose Down
-- +goose StatementBegin
-- Irreversible pre-release reseed: just drop the gates (the stub
-- topology is not restored). Sectors keep their StarWind names.
DELETE FROM gates;
-- +goose StatementEnd
